def test_simple_add():
    calc = ExpressionCalculator()
    assert calc.evaluate('2 + 3') == 5

def test_precedence():
    calc = ExpressionCalculator()
    assert calc.evaluate('2 + 3 * 4') == 14

def test_parentheses():
    calc = ExpressionCalculator()
    assert calc.evaluate('(2 + 3) * 4') == 20

def test_nested_parens():
    calc = ExpressionCalculator()
    assert calc.evaluate('((2 + 3) * (4 - 1))') == 15

def test_unary_minus():
    calc = ExpressionCalculator()
    assert calc.evaluate('-5 + 3') == -2

def test_division():
    calc = ExpressionCalculator()
    assert calc.evaluate('10 // 3') == 3

def test_complex():
    calc = ExpressionCalculator()
    assert calc.evaluate('2 * (3 + 4) - 8 // 2') == 10

def test_single_number():
    calc = ExpressionCalculator()
    assert calc.evaluate('42') == 42
